32: // An Inhibitor determines whether a given label set is muted based on the
33: // currently active alerts and a set of inhibition rules. It implements the
34: // Muter interface.
35: type Inhibitor struct {
36: 	alerts provider.Alerts
37: 	rules  []*InhibitRule
38: 	marker types.AlertMarker
39: 	logger *slog.Logger
40: 
41: 	mtx    sync.RWMutex
42: 	cancel func()
43: }
44: 
45: // NewInhibitor returns a new Inhibitor.
46: func NewInhibitor(ap provider.Alerts, rs []config.InhibitRule, mk types.AlertMarker, logger *slog.Logger) *Inhibitor {
47: 	ih := &Inhibitor{
48: 		alerts: ap,
49: 		marker: mk,
50: 		logger: logger,
51: 	}
52: 	for _, cr := range rs {
53: 		r := NewInhibitRule(cr)
54: 		ih.rules = append(ih.rules, r)
55: 	}
56: 	return ih
57: }
58: 
59: func (ih *Inhibitor) run(ctx context.Context) {
60: 	it := ih.alerts.Subscribe()
61: 	defer it.Close()
62: 
63: 	for {
64: 		select {
65: 		case <-ctx.Done():
66: 			return
67: 		case a := <-it.Next():
68: 			if err := it.Err(); err != nil {
69: 				ih.logger.Error("Error iterating alerts", "err", err)
70: 				continue
71: 			}
72: 			// Update the inhibition rules' cache.
73: 			for _, r := range ih.rules {
74: 				if r.SourceMatchers.Matches(a.Labels) {
75: 					if err := r.scache.Set(a); err != nil {
76: 						ih.logger.Error("error on set alert", "err", err)
77: 					}
78: 				}
79: 			}
80: 		}
81: 	}
82: }
83: 
84: // Run the Inhibitor's background processing.
85: func (ih *Inhibitor) Run() {
86: 	var (
87: 		g   run.Group
88: 		ctx context.Context
89: 	)
90: 
91: 	ih.mtx.Lock()
92: 	ctx, ih.cancel = context.WithCancel(context.Background())
93: 	ih.mtx.Unlock()
94: 	runCtx, runCancel := context.WithCancel(ctx)
95: 
96: 	for _, rule := range ih.rules {
97: 		go rule.scache.Run(runCtx, 15*time.Minute)
98: 	}
99: 
100: 	g.Add(func() error {
101: 		ih.run(runCtx)
102: 		return nil
103: 	}, func(err error) {
104: 		runCancel()
105: 	})
106: 
107: 	if err := g.Run(); err != nil {
108: 		ih.logger.Warn("error running inhibitor", "err", err)
109: 	}
110: }
111: 
112: // Stop the Inhibitor's background processing.
113: func (ih *Inhibitor) Stop() {
114: 	if ih == nil {
115: 		return
116: 	}
117: 
118: 	ih.mtx.RLock()
119: 	defer ih.mtx.RUnlock()
120: 	if ih.cancel != nil {
121: 		ih.cancel()
122: 	}
123: }
124: 
125: // Mutes returns true iff the given label set is muted. It implements the Muter
126: // interface.
127: func (ih *Inhibitor) Mutes(lset model.LabelSet) bool {
128: 	fp := lset.Fingerprint()
129: 
130: 	for _, r := range ih.rules {
131: 		if !r.TargetMatchers.Matches(lset) {
132: 			// If target side of rule doesn't match, we don't need to look any further.
133: 			continue
134: 		}
135: 		// If we are here, the target side matches. If the source side matches, too, we
136: 		// need to exclude inhibiting alerts for which the same is true.
137: 		if inhibitedByFP, eq := r.hasEqual(lset, r.SourceMatchers.Matches(lset)); eq {
138: 			ih.marker.SetInhibited(fp, inhibitedByFP.String())
139: 			return true
140: 		}
141: 	}
142: 	ih.marker.SetInhibited(fp)
143: 
144: 	return false
145: }
146: 
147: // An InhibitRule specifies that a class of (source) alerts should inhibit
148: // notifications for another class of (target) alerts if all specified matching
149: // labels are equal between the two alerts. This may be used to inhibit alerts
150: // from sending notifications if their meaning is logically a subset of a
151: // higher-level alert.
152: type InhibitRule struct {
153: 	// The set of Filters which define the group of source alerts (which inhibit
154: 	// the target alerts).
155: 	SourceMatchers labels.Matchers
156: 	// The set of Filters which define the group of target alerts (which are
157: 	// inhibited by the source alerts).
158: 	TargetMatchers labels.Matchers
159: 	// A set of label names whose label values need to be identical in source and
160: 	// target alerts in order for the inhibition to take effect.
161: 	Equal map[model.LabelName]struct{}
162: 
163: 	// Cache of alerts matching source labels.
164: 	scache *store.Alerts
165: }
166: 
167: // NewInhibitRule returns a new InhibitRule based on a configuration definition.
168: func NewInhibitRule(cr config.InhibitRule) *InhibitRule {
169: 	var (
170: 		sourcem labels.Matchers
171: 		targetm labels.Matchers
172: 	)
173: 	// cr.SourceMatch will be deprecated. This for loop appends regex matchers.
174: 	for ln, lv := range cr.SourceMatch {
175: 		matcher, err := labels.NewMatcher(labels.MatchEqual, ln, lv)
176: 		if err != nil {
177: 			// This error must not happen because the config already validates the yaml.
178: 			panic(err)
179: 		}
180: 		sourcem = append(sourcem, matcher)
181: 	}
182: 	// cr.SourceMatchRE will be deprecated. This for loop appends regex matchers.
183: 	for ln, lv := range cr.SourceMatchRE {
184: 		matcher, err := labels.NewMatcher(labels.MatchRegexp, ln, lv.String())
185: 		if err != nil {
186: 			// This error must not happen because the config already validates the yaml.
187: 			panic(err)
188: 		}
189: 		sourcem = append(sourcem, matcher)
190: 	}
191: 	// We append the new-style matchers. This can be simplified once the deprecated matcher syntax is removed.
192: 	sourcem = append(sourcem, cr.SourceMatchers...)
193: 
194: 	// cr.TargetMatch will be deprecated. This for loop appends regex matchers.
195: 	for ln, lv := range cr.TargetMatch {
196: 		matcher, err := labels.NewMatcher(labels.MatchEqual, ln, lv)
197: 		if err != nil {
198: 			// This error must not happen because the config already validates the yaml.
199: 			panic(err)
200: 		}
201: 		targetm = append(targetm, matcher)
202: 	}
203: 	// cr.TargetMatchRE will be deprecated. This for loop appends regex matchers.
204: 	for ln, lv := range cr.TargetMatchRE {
205: 		matcher, err := labels.NewMatcher(labels.MatchRegexp, ln, lv.String())
206: 		if err != nil {
207: 			// This error must not happen because the config already validates the yaml.
208: 			panic(err)
209: 		}
210: 		targetm = append(targetm, matcher)
211: 	}
212: 	// We append the new-style matchers. This can be simplified once the deprecated matcher syntax is removed.
213: 	targetm = append(targetm, cr.TargetMatchers...)
214: 
215: 	equal := map[model.LabelName]struct{}{}
216: 	for _, ln := range cr.Equal {
217: 		equal[model.LabelName(ln)] = struct{}{}
218: 	}
219: 
220: 	return &InhibitRule{
221: 		SourceMatchers: sourcem,
222: 		TargetMatchers: targetm,
223: 		Equal:          equal,
224: 		scache:         store.NewAlerts(),
225: 	}
226: }
227: 
228: // hasEqual checks whether the source cache contains alerts matching the equal
229: // labels for the given label set. If so, the fingerprint of one of those alerts
230: // is returned. If excludeTwoSidedMatch is true, alerts that match both the
231: // source and the target side of the rule are disregarded.
232: func (r *InhibitRule) hasEqual(lset model.LabelSet, excludeTwoSidedMatch bool) (model.Fingerprint, bool) {
233: 	now := time.Now()
234: Outer:
235: 	for _, a := range r.scache.List() {
236: 		// The cache might be stale and contain resolved alerts.
237: 		if a.ResolvedAt(now) {
238: 			continue
239: 		}
240: 		for n := range r.Equal {
241: 			if a.Labels[n] != lset[n] {
242: 				continue Outer
243: 			}
244: 		}
245: 		if excludeTwoSidedMatch && r.TargetMatchers.Matches(a.Labels) {
246: 			continue Outer
247: 		}
248: 		return a.Fingerprint(), true
249: 	}
250: 	return model.Fingerprint(0), false
251: }
