189: // Silences holds a silence state that can be modified, queried, and snapshot.
190: type Silences struct {
191: 	clock quartz.Clock
192: 
193: 	logger    *slog.Logger
194: 	metrics   *metrics
195: 	retention time.Duration
196: 	limits    Limits
197: 
198: 	mtx       sync.RWMutex
199: 	st        state
200: 	version   int // Increments whenever silences are added.
201: 	broadcast func([]byte)
202: 	mc        matcherCache
203: }
