205: // Limits contains the limits for silences.
206: type Limits struct {
207: 	// MaxSilences limits the maximum number of silences, including expired
208: 	// silences.
209: 	MaxSilences func() int
210: 	// MaxSilenceSizeBytes is the maximum size of an individual silence as
211: 	// stored on disk.
212: 	MaxSilenceSizeBytes func() int
