234: func newSilenceMetricByState(s *Silences, st types.SilenceState) prometheus.GaugeFunc {
235: 	return prometheus.NewGaugeFunc(
236: 		prometheus.GaugeOpts{
237: 			Name:        "alertmanager_silences",
238: 			Help:        "How many silences by state.",
239: 			ConstLabels: prometheus.Labels{"state": string(st)},
240: 		},
241: 		func() float64 {
242: 			count, err := s.CountState(st)
243: 			if err != nil {
244: 				s.logger.Error("Counting silences failed", "err", err)
245: 			}
246: 			return float64(count)
247: 		},
248: 	)
249: }
