251: func newMetrics(r prometheus.Registerer, s *Silences) *metrics {
252: 	m := &metrics{}
253: 
254: 	m.gcDuration = prometheus.NewSummary(prometheus.SummaryOpts{
255: 		Name:       "alertmanager_silences_gc_duration_seconds",
256: 		Help:       "Duration of the last silence garbage collection cycle.",
257: 		Objectives: map[float64]float64{},
258: 	})
259: 	m.snapshotDuration = prometheus.NewSummary(prometheus.SummaryOpts{
260: 		Name:       "alertmanager_silences_snapshot_duration_seconds",
261: 		Help:       "Duration of the last silence snapshot.",
262: 		Objectives: map[float64]float64{},
263: 	})
264: 	m.snapshotSize = prometheus.NewGauge(prometheus.GaugeOpts{
265: 		Name: "alertmanager_silences_snapshot_size_bytes",
266: 		Help: "Size of the last silence snapshot in bytes.",
267: 	})
268: 	m.maintenanceTotal = prometheus.NewCounter(prometheus.CounterOpts{
269: 		Name: "alertmanager_silences_maintenance_total",
270: 		Help: "How many maintenances were executed for silences.",
271: 	})
272: 	m.maintenanceErrorsTotal = prometheus.NewCounter(prometheus.CounterOpts{
273: 		Name: "alertmanager_silences_maintenance_errors_total",
274: 		Help: "How many maintenances were executed for silences that failed.",
275: 	})
276: 	m.queriesTotal = prometheus.NewCounter(prometheus.CounterOpts{
277: 		Name: "alertmanager_silences_queries_total",
278: 		Help: "How many silence queries were received.",
279: 	})
280: 	m.queryErrorsTotal = prometheus.NewCounter(prometheus.CounterOpts{
281: 		Name: "alertmanager_silences_query_errors_total",
282: 		Help: "How many silence received queries did not succeed.",
283: 	})
284: 	m.queryDuration = prometheus.NewHistogram(prometheus.HistogramOpts{
285: 		Name:                            "alertmanager_silences_query_duration_seconds",
286: 		Help:                            "Duration of silence query evaluation.",
287: 		Buckets:                         prometheus.DefBuckets,
288: 		NativeHistogramBucketFactor:     1.1,
289: 		NativeHistogramMaxBucketNumber:  100,
290: 		NativeHistogramMinResetDuration: 1 * time.Hour,
291: 	})
292: 	m.propagatedMessagesTotal = prometheus.NewCounter(prometheus.CounterOpts{
293: 		Name: "alertmanager_silences_gossip_messages_propagated_total",
294: 		Help: "Number of received gossip messages that have been further gossiped.",
295: 	})
296: 	if s != nil {
297: 		m.silencesActive = newSilenceMetricByState(s, types.SilenceStateActive)
298: 		m.silencesPending = newSilenceMetricByState(s, types.SilenceStatePending)
299: 		m.silencesExpired = newSilenceMetricByState(s, types.SilenceStateExpired)
300: 	}
301: 
302: 	if r != nil {
303: 		r.MustRegister(
304: 			m.gcDuration,
305: 			m.snapshotDuration,
306: 			m.snapshotSize,
307: 			m.queriesTotal,
308: 			m.queryErrorsTotal,
309: 			m.queryDuration,
310: 			m.silencesActive,
311: 			m.silencesPending,
312: 			m.silencesExpired,
313: 			m.propagatedMessagesTotal,
314: 			m.maintenanceTotal,
315: 			m.maintenanceErrorsTotal,
316: 		)
317: 	}
318: 	return m
319: }
