321: // Options exposes configuration options for creating a new Silences object.
322: // Its zero value is a safe default.
323: type Options struct {
324: 	// A snapshot file or reader from which the initial state is loaded.
325: 	// None or only one of them must be set.
326: 	SnapshotFile   string
327: 	SnapshotReader io.Reader
328: 
329: 	// Retention time for newly created Silences. Silences may be
330: 	// garbage collected after the given duration after they ended.
331: 	Retention time.Duration
332: 	Limits    Limits
333: 
334: 	// A logger used by background processing.
335: 	Logger  *slog.Logger
336: 	Metrics prometheus.Registerer
337: }
338: 
339: func (o *Options) validate() error {
340: 	if o.SnapshotFile != "" && o.SnapshotReader != nil {
341: 		return errors.New("only one of SnapshotFile and SnapshotReader must be set")
342: 	}
343: 	return nil
344: }
345: 
346: // New returns a new Silences object with the given configuration.
347: func New(o Options) (*Silences, error) {
348: 	if err := o.validate(); err != nil {
349: 		return nil, err
350: 	}
351: 
352: 	s := &Silences{
353: 		clock:     quartz.NewReal(),
354: 		mc:        matcherCache{},
355: 		logger:    promslog.NewNopLogger(),
356: 		retention: o.Retention,
357: 		limits:    o.Limits,
358: 		broadcast: func([]byte) {},
359: 		st:        state{},
360: 	}
361: 	s.metrics = newMetrics(o.Metrics, s)
362: 
363: 	if o.Logger != nil {
364: 		s.logger = o.Logger
365: 	}
366: 
367: 	if o.SnapshotFile != "" {
368: 		if r, err := os.Open(o.SnapshotFile); err != nil {
369: 			if !os.IsNotExist(err) {
370: 				return nil, err
371: 			}
372: 			s.logger.Debug("silences snapshot file doesn't exist", "err", err)
373: 		} else {
374: 			o.SnapshotReader = r
375: 			defer r.Close()
376: 		}
377: 	}
378: 
379: 	if o.SnapshotReader != nil {
380: 		if err := s.loadSnapshot(o.SnapshotReader); err != nil {
381: 			return s, err
382: 		}
383: 	}
384: 	return s, nil
385: }
