387: func (s *Silences) nowUTC() time.Time {
388: 	return s.clock.Now().UTC()
389: }
390: 
391: // Maintenance garbage collects the silence state at the given interval. If the snapshot
392: // file is set, a snapshot is written to it afterwards.
393: // Terminates on receiving from stopc.
394: // If not nil, the last argument is an override for what to do as part of the maintenance - for advanced usage.
395: func (s *Silences) Maintenance(interval time.Duration, snapf string, stopc <-chan struct{}, override MaintenanceFunc) {
396: 	if interval == 0 || stopc == nil {
397: 		s.logger.Error("interval or stop signal are missing - not running maintenance")
398: 		return
399: 	}
400: 	t := s.clock.NewTicker(interval)
401: 	defer t.Stop()
402: 
403: 	var doMaintenance MaintenanceFunc
404: 	doMaintenance = func() (int64, error) {
405: 		var size int64
406: 
407: 		if _, err := s.GC(); err != nil {
408: 			return size, err
409: 		}
410: 		if snapf == "" {
411: 			return size, nil
412: 		}
413: 		f, err := openReplace(snapf)
414: 		if err != nil {
415: 			return size, err
416: 		}
417: 		if size, err = s.Snapshot(f); err != nil {
418: 			f.Close()
419: 			return size, err
420: 		}
421: 		return size, f.Close()
422: 	}
423: 
424: 	if override != nil {
425: 		doMaintenance = override
426: 	}
427: 
428: 	runMaintenance := func(do MaintenanceFunc) error {
429: 		s.metrics.maintenanceTotal.Inc()
430: 		s.logger.Debug("Running maintenance")
431: 		start := s.nowUTC()
432: 		size, err := do()
433: 		s.metrics.snapshotSize.Set(float64(size))
434: 		if err != nil {
435: 			s.metrics.maintenanceErrorsTotal.Inc()
436: 			return err
437: 		}
438: 		s.logger.Debug("Maintenance done", "duration", s.clock.Since(start), "size", size)
439: 		return nil
440: 	}
441: 
442: Loop:
443: 	for {
444: 		select {
445: 		case <-stopc:
446: 			break Loop
447: 		case <-t.C:
448: 			if err := runMaintenance(doMaintenance); err != nil {
449: 				// @tjhop: this should probably log at error level
450: 				s.logger.Info("Running maintenance failed", "err", err)
451: 			}
452: 		}
453: 	}
454: 
455: 	// No need for final maintenance if we don't want to snapshot.
456: 	if snapf == "" {
457: 		return
458: 	}
459: 	if err := runMaintenance(doMaintenance); err != nil {
460: 		// @tjhop: this should probably log at error level
461: 		s.logger.Info("Creating shutdown snapshot failed", "err", err)
462: 	}
463: }
