465: // GC runs a garbage collection that removes silences that have ended longer
466: // than the configured retention time ago.
467: func (s *Silences) GC() (int, error) {
468: 	start := time.Now()
469: 	defer func() { s.metrics.gcDuration.Observe(time.Since(start).Seconds()) }()
470: 
471: 	now := s.nowUTC()
472: 	var n int
473: 
474: 	s.mtx.Lock()
475: 	defer s.mtx.Unlock()
476: 
477: 	for id, sil := range s.st {
478: 		if sil.ExpiresAt.IsZero() {
479: 			return n, errors.New("unexpected zero expiration timestamp")
480: 		}
481: 		if !sil.ExpiresAt.After(now) {
482: 			delete(s.st, id)
483: 			delete(s.mc, sil.Silence.Id)
484: 			n++
485: 		}
486: 	}
487: 
488: 	return n, nil
489: }
