593: // Set the specified silence. If a silence with the ID already exists and the modification
594: // modifies history, the old silence gets expired and a new one is created.
595: func (s *Silences) Set(sil *pb.Silence) error {
596: 	s.mtx.Lock()
597: 	defer s.mtx.Unlock()
598: 
599: 	now := s.nowUTC()
600: 	if sil.StartsAt.IsZero() {
601: 		sil.StartsAt = now
602: 	}
603: 
604: 	if err := validateSilence(sil); err != nil {
605: 		return fmt.Errorf("invalid silence: %w", err)
606: 	}
607: 
608: 	prev, ok := s.getSilence(sil.Id)
609: 	if sil.Id != "" && !ok {
610: 		return ErrNotFound
611: 	}
612: 
613: 	if ok && canUpdate(prev, sil, now) {
614: 		sil.UpdatedAt = now
615: 		msil := s.toMeshSilence(sil)
616: 		if err := s.checkSizeLimits(msil); err != nil {
617: 			return err
618: 		}
619: 		return s.setSilence(msil, now)
620: 	}
621: 
622: 	// If we got here it's either a new silence or a replacing one (which would
623: 	// also create a new silence) so we need to make sure we have capacity for
624: 	// the new silence.
625: 	if s.limits.MaxSilences != nil {
626: 		if m := s.limits.MaxSilences(); m > 0 && len(s.st)+1 > m {
627: 			return fmt.Errorf("exceeded maximum number of silences: %d (limit: %d)", len(s.st), m)
628: 		}
629: 	}
630: 
631: 	uid, err := uuid.NewV4()
632: 	if err != nil {
633: 		return fmt.Errorf("generate uuid: %w", err)
634: 	}
635: 	sil.Id = uid.String()
636: 
637: 	if sil.StartsAt.Before(now) {
638: 		sil.StartsAt = now
639: 	}
640: 	sil.UpdatedAt = now
641: 
642: 	msil := s.toMeshSilence(sil)
643: 	if err := s.checkSizeLimits(msil); err != nil {
644: 		return err
645: 	}
646: 
647: 	if ok && getState(prev, s.nowUTC()) != types.SilenceStateExpired {
648: 		// We cannot update the silence, expire the old one to leave a history of
649: 		// the silence before modification.
650: 		if err := s.expire(prev.Id); err != nil {
651: 			return fmt.Errorf("expire previous silence: %w", err)
652: 		}
653: 	}
654: 
655: 	return s.setSilence(msil, now)
656: }
657: 
658: // canUpdate returns true if silence a can be updated to b without
659: // affecting the historic view of silencing.
660: func canUpdate(a, b *pb.Silence, now time.Time) bool {
661: 	if !reflect.DeepEqual(a.Matchers, b.Matchers) {
662: 		return false
663: 	}
664: 	// Allowed timestamp modifications depend on the current time.
665: 	switch st := getState(a, now); st {
666: 	case types.SilenceStateActive:
667: 		if b.StartsAt.Unix() != a.StartsAt.Unix() {
668: 			return false
669: 		}
670: 		if b.EndsAt.Before(now) {
671: 			return false
672: 		}
673: 	case types.SilenceStatePending:
674: 		if b.StartsAt.Before(now) {
675: 			return false
676: 		}
677: 	case types.SilenceStateExpired:
678: 		return false
679: 	default:
680: 		panic("unknown silence state")
681: 	}
682: 	return true
683: }
684: 
685: // Expire the silence with the given ID immediately.
686: func (s *Silences) Expire(id string) error {
687: 	s.mtx.Lock()
688: 	defer s.mtx.Unlock()
689: 	return s.expire(id)
690: }
691: 
692: // Expire the silence with the given ID immediately.
693: // It is idempotent, nil is returned if the silence already expired before it is GC'd.
694: // If the silence is not found an error is returned.
695: func (s *Silences) expire(id string) error {
696: 	sil, ok := s.getSilence(id)
697: 	if !ok {
698: 		return ErrNotFound
699: 	}
700: 	sil = cloneSilence(sil)
701: 	now := s.nowUTC()
702: 
703: 	switch getState(sil, now) {
704: 	case types.SilenceStateExpired:
705: 		return nil
706: 	case types.SilenceStateActive:
707: 		sil.EndsAt = now
708: 	case types.SilenceStatePending:
709: 		// Set both to now to make Silence move to "expired" state
710: 		sil.StartsAt = now
711: 		sil.EndsAt = now
712: 	}
713: 	sil.UpdatedAt = now
714: 	return s.setSilence(s.toMeshSilence(sil), now)
715: }
