717: // QueryParam expresses parameters along which silences are queried.
718: type QueryParam func(*query) error
719: 
720: type query struct {
721: 	ids     []string
722: 	filters []silenceFilter
723: }
724: 
725: // silenceFilter is a function that returns true if a silence
726: // should be dropped from a result set for a given time.
727: type silenceFilter func(*pb.Silence, *Silences, time.Time) (bool, error)
728: 
729: // QIDs configures a query to select the given silence IDs.
730: func QIDs(ids ...string) QueryParam {
731: 	return func(q *query) error {
732: 		q.ids = append(q.ids, ids...)
733: 		return nil
734: 	}
735: }
736: 
737: // QMatches returns silences that match the given label set.
738: func QMatches(set model.LabelSet) QueryParam {
739: 	return func(q *query) error {
740: 		f := func(sil *pb.Silence, s *Silences, _ time.Time) (bool, error) {
741: 			m, err := s.mc.Get(sil)
742: 			if err != nil {
743: 				return true, err
744: 			}
745: 			return m.Matches(set), nil
746: 		}
747: 		q.filters = append(q.filters, f)
748: 		return nil
749: 	}
750: }
751: 
752: // getState returns a silence's SilenceState at the given timestamp.
753: func getState(sil *pb.Silence, ts time.Time) types.SilenceState {
754: 	if ts.Before(sil.StartsAt) {
755: 		return types.SilenceStatePending
756: 	}
757: 	if ts.After(sil.EndsAt) {
758: 		return types.SilenceStateExpired
759: 	}
760: 	return types.SilenceStateActive
761: }
762: 
763: // QState filters queried silences by the given states.
764: func QState(states ...types.SilenceState) QueryParam {
765: 	return func(q *query) error {
766: 		f := func(sil *pb.Silence, _ *Silences, now time.Time) (bool, error) {
767: 			s := getState(sil, now)
768: 
769: 			for _, ps := range states {
770: 				if s == ps {
771: 					return true, nil
772: 				}
773: 			}
774: 			return false, nil
775: 		}
776: 		q.filters = append(q.filters, f)
777: 		return nil
778: 	}
779: }
