781: // QueryOne queries with the given parameters and returns the first result.
782: // Returns ErrNotFound if the query result is empty.
783: func (s *Silences) QueryOne(params ...QueryParam) (*pb.Silence, error) {
784: 	res, _, err := s.Query(params...)
785: 	if err != nil {
786: 		return nil, err
787: 	}
788: 	if len(res) == 0 {
789: 		return nil, ErrNotFound
790: 	}
791: 	return res[0], nil
792: }
