794: // Query for silences based on the given query parameters. It returns the
795: // resulting silences and the state version the result is based on.
796: func (s *Silences) Query(params ...QueryParam) ([]*pb.Silence, int, error) {
797: 	s.mtx.Lock()
798: 	defer s.mtx.Unlock()
799: 
800: 	s.metrics.queriesTotal.Inc()
801: 	defer prometheus.NewTimer(s.metrics.queryDuration).ObserveDuration()
802: 
803: 	q := &query{}
804: 	for _, p := range params {
805: 		if err := p(q); err != nil {
806: 			s.metrics.queryErrorsTotal.Inc()
807: 			return nil, s.Version(), err
808: 		}
809: 	}
810: 	sils, version, err := s.query(q, s.nowUTC())
811: 	if err != nil {
812: 		s.metrics.queryErrorsTotal.Inc()
813: 	}
814: 	return sils, version, err
815: }
