834: func (s *Silences) query(q *query, now time.Time) ([]*pb.Silence, int, error) {
835: 	// If we have no ID constraint, all silences are our base set.  This and
836: 	// the use of post-filter functions is the trivial solution for now.
837: 	var res []*pb.Silence
838: 
839: 	if q.ids != nil {
840: 		for _, id := range q.ids {
841: 			if s, ok := s.st[id]; ok {
842: 				res = append(res, s.Silence)
843: 			}
844: 		}
845: 	} else {
846: 		for _, sil := range s.st {
847: 			res = append(res, sil.Silence)
848: 		}
849: 	}
850: 
851: 	var resf []*pb.Silence
852: 	for _, sil := range res {
853: 		remove := false
854: 		for _, f := range q.filters {
855: 			ok, err := f(sil, s, now)
856: 			if err != nil {
857: 				return nil, s.version, err
858: 			}
859: 			if !ok {
860: 				remove = true
861: 				break
862: 			}
863: 		}
864: 		if !remove {
865: 			resf = append(resf, cloneSilence(sil))
866: 		}
867: 	}
868: 
869: 	return resf, s.version, nil
870: }
