872: // loadSnapshot loads a snapshot generated by Snapshot() into the state.
873: // Any previous state is wiped.
874: func (s *Silences) loadSnapshot(r io.Reader) error {
875: 	st, err := decodeState(r)
876: 	if err != nil {
877: 		return err
878: 	}
879: 	for _, e := range st {
880: 		// Comments list was moved to a single comment. Upgrade on loading the snapshot.
881: 		if len(e.Silence.Comments) > 0 {
882: 			e.Silence.Comment = e.Silence.Comments[0].Comment
883: 			e.Silence.CreatedBy = e.Silence.Comments[0].Author
884: 			e.Silence.Comments = nil
885: 		}
886: 		st[e.Silence.Id] = e
887: 	}
888: 	s.mtx.Lock()
889: 	s.st = st
890: 	s.version++
891: 	s.mtx.Unlock()
892: 
893: 	return nil
894: }
