896: // Snapshot writes the full internal state into the writer and returns the number of bytes
897: // written.
898: func (s *Silences) Snapshot(w io.Writer) (int64, error) {
899: 	start := time.Now()
900: 	defer func() { s.metrics.snapshotDuration.Observe(time.Since(start).Seconds()) }()
901: 
902: 	s.mtx.RLock()
903: 	defer s.mtx.RUnlock()
904: 
905: 	b, err := s.st.MarshalBinary()
906: 	if err != nil {
907: 		return 0, err
908: 	}
909: 
910: 	return io.Copy(w, bytes.NewReader(b))
911: }
