913: // MarshalBinary serializes all silences.
914: func (s *Silences) MarshalBinary() ([]byte, error) {
915: 	s.mtx.Lock()
916: 	defer s.mtx.Unlock()
917: 
918: 	return s.st.MarshalBinary()
919: }
