921: // Merge merges silence state received from the cluster with the local state.
922: func (s *Silences) Merge(b []byte) error {
923: 	st, err := decodeState(bytes.NewReader(b))
924: 	if err != nil {
925: 		return err
926: 	}
927: 	s.mtx.Lock()
928: 	defer s.mtx.Unlock()
929: 
930: 	now := s.nowUTC()
931: 
932: 	for _, e := range st {
933: 		merged, added := s.st.merge(e, now)
934: 		if merged {
935: 			if added {
936: 				s.version++
937: 			}
938: 			if !cluster.OversizedMessage(b) {
939: 				// If this is the first we've seen the message and it's
940: 				// not oversized, gossip it to other nodes. We don't
941: 				// propagate oversized messages because they're sent to
942: 				// all nodes already.
943: 				s.broadcast(b)
944: 				s.metrics.propagatedMessagesTotal.Inc()
945: 				s.logger.Debug("Gossiping new silence", "silence", e)
946: 			}
947: 		}
948: 	}
949: 	return nil
950: }
951: 
952: // SetBroadcast sets the provided function as the one creating data to be
953: // broadcast.
954: func (s *Silences) SetBroadcast(f func([]byte)) {
955: 	s.mtx.Lock()
956: 	s.broadcast = f
957: 	s.mtx.Unlock()
958: }
959: 
960: type state map[string]*pb.MeshSilence
961: 
962: // merge returns two bools: the first is true when merge caused a state change. The second
963: // is true if that state change added a new silence. In other words, the second return is
964: // true whenever a silence with a new ID has been added to the state as a result of merge.
965: func (s state) merge(e *pb.MeshSilence, now time.Time) (bool, bool) {
966: 	id := e.Silence.Id
967: 	if e.ExpiresAt.Before(now) {
968: 		return false, false
969: 	}
970: 	// Comments list was moved to a single comment. Apply upgrade
971: 	// on silences received from peers.
972: 	if len(e.Silence.Comments) > 0 {
973: 		e.Silence.Comment = e.Silence.Comments[0].Comment
974: 		e.Silence.CreatedBy = e.Silence.Comments[0].Author
975: 		e.Silence.Comments = nil
976: 	}
977: 
978: 	prev, ok := s[id]
979: 	if !ok || prev.Silence.UpdatedAt.Before(e.Silence.UpdatedAt) {
980: 		s[id] = e
981: 		return true, !ok
982: 	}
983: 	return false, false
984: }
985: 
