313: func (api *API) postAlertsHandler(params alert_ops.PostAlertsParams) middleware.Responder {
314: 	logger := api.requestLogger(params.HTTPRequest)
315: 
316: 	alerts := OpenAPIAlertsToAlerts(params.Alerts)
317: 	now := time.Now()
318: 
319: 	api.mtx.RLock()
320: 	resolveTimeout := time.Duration(api.alertmanagerConfig.Global.ResolveTimeout)
321: 	api.mtx.RUnlock()
322: 
323: 	for _, alert := range alerts {
324: 		alert.UpdatedAt = now
325: 
326: 		// Ensure StartsAt is set.
327: 		if alert.StartsAt.IsZero() {
328: 			if alert.EndsAt.IsZero() {
329: 				alert.StartsAt = now
330: 			} else {
331: 				alert.StartsAt = alert.EndsAt
332: 			}
333: 		}
334: 		// If no end time is defined, set a timeout after which an alert
335: 		// is marked resolved if it is not updated.
336: 		if alert.EndsAt.IsZero() {
337: 			alert.Timeout = true
338: 			alert.EndsAt = now.Add(resolveTimeout)
339: 		}
340: 		if alert.EndsAt.After(time.Now()) {
341: 			api.m.Firing().Inc()
342: 		} else {
343: 			api.m.Resolved().Inc()
344: 		}
345: 	}
346: 
347: 	// Make a best effort to insert all alerts that are valid.
348: 	var (
349: 		validAlerts    = make([]*types.Alert, 0, len(alerts))
350: 		validationErrs = &types.MultiError{}
351: 	)
352: 	for _, a := range alerts {
353: 		removeEmptyLabels(a.Labels)
354: 
355: 		if err := a.Validate(); err != nil {
356: 			validationErrs.Add(err)
357: 			api.m.Invalid().Inc()
358: 			continue
359: 		}
360: 		validAlerts = append(validAlerts, a)
361: 	}
362: 	if err := api.alerts.Put(validAlerts...); err != nil {
363: 		logger.Error("Failed to create alerts", "err", err)
364: 		return alert_ops.NewPostAlertsInternalServerError().WithPayload(err.Error())
365: 	}
366: 
367: 	if validationErrs.Len() > 0 {
368: 		logger.Error("Failed to validate alerts", "err", validationErrs.Error())
369: 		return alert_ops.NewPostAlertsBadRequest().WithPayload(validationErrs.Error())
370: 	}
371: 
372: 	return alert_ops.NewPostAlertsOK()
373: }
